/**
 * @name XStream deserialization: class name from XML flows to class loading
 * @description Traces how class names read from XML input flow into Class.forName or loadClass
 * @kind path-problem
 * @problem.severity error
 * @id java/xstream-classname-to-classloading
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module ClassNameTaintConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Source: reading node names/values from XML stream (HierarchicalStreamReader)
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("getNodeName") or
        mc.getMethod().hasName("getValue") or
        mc.getMethod().hasName("getAttribute")
      ) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName(
        "com.thoughtworks.xstream.io", "HierarchicalStreamReader"
      ) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Sink 1: Class.forName
    exists(MethodCall mc |
      mc.getMethod().hasName("forName") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Class") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Sink 2: ClassLoader.loadClass
    exists(MethodCall mc |
      mc.getMethod().hasName("loadClass") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "ClassLoader") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module ClassNameTaintFlow = TaintTracking::Global<ClassNameTaintConfig>;
import ClassNameTaintFlow::PathGraph

from ClassNameTaintFlow::PathNode source, ClassNameTaintFlow::PathNode sink
where ClassNameTaintFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Class name from XML input $@ flows to class loading.", source.getNode(), "XML reader value"

/**
 * @name XStream DynamicProxyConverter: XML class name to dynamic proxy with arbitrary interfaces
 * @description DynamicProxyConverter reads interface class names from XML and creates dynamic proxies
 *              which can be used as gadget chains for OS command injection
 * @kind path-problem
 * @problem.severity error
 * @id java/xstream-dynamic-proxy-cmd-injection
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module DynProxyConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Source: reading values/node names from XML
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("getNodeName") or
        mc.getMethod().hasName("getValue") or
        mc.getMethod().hasName("getAttribute")
      ) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName(
        "com.thoughtworks.xstream.io", "HierarchicalStreamReader"
      ) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Sink: Proxy.newProxyInstance - dynamic proxy creation with attacker-controlled interfaces
    exists(MethodCall mc |
      mc.getMethod().hasName("newProxyInstance") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang.reflect", "Proxy") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Sink: Class.forName with attacker-controlled class name
    exists(MethodCall mc |
      mc.getMethod().hasName("forName") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Class") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Sink: Class.newInstance
    exists(MethodCall mc |
      mc.getMethod().hasName("newInstance") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Class") and
      sink.asExpr() = mc.getQualifier()
    )
  }
}

module DynProxyFlow = TaintTracking::Global<DynProxyConfig>;
import DynProxyFlow::PathGraph

from DynProxyFlow::PathNode source, DynProxyFlow::PathNode sink
where DynProxyFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "XML input $@ flows to dangerous reflection/proxy operation enabling OS command injection.", source.getNode(), "XML reader value"

/**
 * @name XStream EventHandler gadget chain - ProcessBuilder/Runtime via dynamic proxy
 * @description XStream's DynamicProxyConverter can create a java.lang.reflect.Proxy with 
 *              java.beans.EventHandler as InvocationHandler, which can invoke Runtime.exec()
 *              when any method on the proxy is called. This is the classic XStream RCE gadget.
 * @kind path-problem
 * @problem.severity error
 * @id java/xstream-eventhandler-gadget
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module EventHandlerGadgetConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Source: reading node name or attribute from XML in DynamicProxyConverter
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("getNodeName") or
        mc.getMethod().hasName("getValue") or
        mc.getMethod().hasName("getAttribute") or
        mc.getMethod().hasName("moveDown") or
        mc.getMethod().hasName("moveUp")
      ) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName(
        "com.thoughtworks.xstream.io", "HierarchicalStreamReader"
      ) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Sink: Proxy.newProxyInstance - creating a dynamic proxy with attacker-controlled interfaces/handler
    exists(MethodCall mc |
      mc.getMethod().hasName("newProxyInstance") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang.reflect", "Proxy") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module EventHandlerGadgetFlow = TaintTracking::Global<EventHandlerGadgetConfig>;
import EventHandlerGadgetFlow::PathGraph

from EventHandlerGadgetFlow::PathNode source, EventHandlerGadgetFlow::PathNode sink
where EventHandlerGadgetFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "XML input $@ flows to Proxy.newProxyInstance - enables EventHandler gadget chain for OS command execution.", source.getNode(), "XML reader value"

/**
 * @name XStream DynamicProxyConverter unmarshal - handler from XML to Proxy.newProxyInstance
 * @description In DynamicProxyConverter.unmarshal(), the InvocationHandler is deserialized from
 *              XML and passed directly to Proxy.newProxyInstance, enabling EventHandler gadget RCE
 * @kind path-problem
 * @problem.severity error
 * @id java/xstream-dpc-handler-injection
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module DPCHandlerConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Source: context.convertAnother() - deserializes an object from the XML stream
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("convertAnother") or
        mc.getMethod().hasName("unmarshal")
      ) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName(
        "com.thoughtworks.xstream.converters", "UnmarshallingContext"
      ) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Sink: Proxy.newProxyInstance handler argument (3rd argument, index 2)
    exists(MethodCall mc |
      mc.getMethod().hasName("newProxyInstance") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang.reflect", "Proxy") and
      sink.asExpr() = mc.getArgument(2)
    )
  }
}

module DPCHandlerFlow = TaintTracking::Global<DPCHandlerConfig>;
import DPCHandlerFlow::PathGraph

from DPCHandlerFlow::PathNode source, DPCHandlerFlow::PathNode sink
where DPCHandlerFlow::flowPath(source, sink)
select sink.getNode(), source, sink,
  "Deserialized XML object $@ used as InvocationHandler in Proxy.newProxyInstance - attacker can supply EventHandler pointing to Runtime.exec()",
  source.getNode(), "convertAnother()"

/**
 * @name XStream gadget: unmarshalled objects flowing to exec/command execution
 * @description Finds paths where objects deserialized from XML can trigger command execution
 *              through gadget chains (EventHandler, ProcessBuilder, etc.)
 * @kind path-problem
 * @problem.severity error
 * @id java/xstream-unmarshal-to-exec
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module UnmarshalExecConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Source: convertAnother in unmarshalling context - returns deserialized objects from XML
    exists(MethodCall mc |
      mc.getMethod().hasName("convertAnother") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName(
        "com.thoughtworks.xstream.converters", "UnmarshallingContext"
      ) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Sink 1: ProcessBuilder constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.lang", "ProcessBuilder") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // Sink 2: Runtime.exec()
    exists(MethodCall mc |
      mc.getMethod().hasName("exec") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Runtime") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Sink 3: Proxy.newProxyInstance handler argument
    exists(MethodCall mc |
      mc.getMethod().hasName("newProxyInstance") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang.reflect", "Proxy") and
      sink.asExpr() = mc.getArgument(2)
    )
    or
    // Sink 4: reflect.Method.invoke() - could trigger arbitrary method calls
    exists(MethodCall mc |
      mc.getMethod().hasName("invoke") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang.reflect", "Method") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module UnmarshalExecFlow = TaintTracking::Global<UnmarshalExecConfig>;
import UnmarshalExecFlow::PathGraph

from UnmarshalExecFlow::PathNode source, UnmarshalExecFlow::PathNode sink
where UnmarshalExecFlow::flowPath(source, sink)
select sink.getNode(), source, sink,
  "Deserialized XML object $@ reaches dangerous operation - possible OS command injection gadget chain.",
  source.getNode(), "deserialized XML object"
